// Poll LambdaTest for the contact-us-e2e-weekly build
const maxAttempts = 20; // 20 * 30s = 10 minutes
const staticData = $getWorkflowStaticData('node');
staticData.pollAttempt = (staticData.pollAttempt || 0) + 1;

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    poll_attempt: staticData.pollAttempt,
    max_attempts: maxAttempts,
    today: today
  }
}];

// Check if build is complete
const pollData = $('Poll Counter').first().json;
const builds = $input.first().json.data || [];

// Find today's build
const todayBuild = builds.find(b => {
  const buildDate = new Date(b.create_timestamp).toISOString().split('T')[0];
  return buildDate === pollData.today;
});

if (!todayBuild) {
  return [{ json: { status: 'not_found', poll_attempt: pollData.poll_attempt, max_attempts: pollData.max_attempts } }];
}

const isComplete = todayBuild.status_ind === 'completed' || todayBuild.status_ind === 'passed' || todayBuild.status_ind === 'failed' || todayBuild.status_ind === 'error';
const isPassed = todayBuild.status_ind === 'completed' || todayBuild.status_ind === 'passed';

return [{
  json: {
    status: isComplete ? (isPassed ? 'passed' : 'failed') : 'running',
    build_id: todayBuild.build_id,
    build_name: todayBuild.name,
    status_ind: todayBuild.status_ind,
    poll_attempt: pollData.poll_attempt,
    max_attempts: pollData.max_attempts
  }
}];

// Consolidate all automated check results
const buildData = $('Cypress Passed?').first().json;
const emailCheck = $('CloudWatch: Email Dispatched?').first().json;
const smsCheck = $('CloudWatch: SMS Sent?').first().json;

const cypressPassed = buildData.status === 'passed';

// CloudWatch StartQuery returns a queryId - we'd need GetQueryResults
// For now, check if the API call succeeded (no error)
const emailDispatched = !emailCheck.error && emailCheck.queryId;
const smsSent = !smsCheck.error && smsCheck.queryId;

const allPassed = cypressPassed && emailDispatched && smsSent;

const failures = [];
if (!cypressPassed) failures.push('cypress_failed');
if (!emailDispatched) failures.push('email_not_dispatched');
if (!smsSent) failures.push('sms_not_sent');

return [{
  json: {
    all_passed: allPassed,
    cypress_passed: cypressPassed,
    email_dispatched: emailDispatched,
    sms_sent: smsSent,
    build_id: buildData.build_id,
    failures: failures,
    timestamp: new Date().toISOString()
  }
}];

// Generate webhook URLs for Evan's YES/NO response
const data = $input.first().json;
const executionId = $execution.id;
const baseUrl = 'REPLACE_WITH_N8N_WEBHOOK_BASE_URL';

return [{
  json: {
    ...data,
    yes_url: baseUrl + '/webhook/contact-us-e2e-confirm?response=yes&executionId=' + executionId,
    no_url: baseUrl + '/webhook/contact-us-e2e-confirm?response=no&executionId=' + executionId,
    execution_id: executionId
  }
}];

// Check Evan's response or timeout
const webhookData = $input.first().json;

// If resumed by webhook, query params will have response=yes or response=no
// If resumed by timeout, no query params
const response = webhookData?.query?.response || 'timeout';

return [{
  json: {
    evan_response: response,
    is_timeout: response === 'timeout',
    is_yes: response === 'yes',
    is_no: response === 'no'
  }
}];

// Parse second-round Evan response
const webhookData = $input.first().json;
const response = webhookData?.query?.response || 'timeout_final';

return [{
  json: {
    evan_response: response,
    is_yes: response === 'yes',
    failure_type: response === 'no' ? 'evan_denied' : 'evan_timeout'
  }
}];

// Classify the failure for diagnosis
const consolidatedData = $('Consolidate Results').first()?.json || {};
const evanResponse = $input.first()?.json?.evan_response || $input.first()?.json?.failure_type || 'unknown';

let failureType = 'unknown';
let failureContext = '';

if (consolidatedData.failures && consolidatedData.failures.length > 0) {
  failureType = consolidatedData.failures[0];
  failureContext = 'Automated check failures: ' + consolidatedData.failures.join(', ');
} else if (evanResponse === 'no' || evanResponse === 'evan_denied') {
  failureType = 'evan_denied';
  failureContext = 'Evan confirmed he did NOT receive the Customer Reach Out email notification.';
} else if (evanResponse === 'timeout_final' || evanResponse === 'evan_timeout') {
  failureType = 'evan_timeout';
  failureContext = 'Evan did not respond to confirmation email within 4 hours.';
}

return [{
  json: {
    failure_type: failureType,
    failure_context: failureContext,
    build_id: consolidatedData.build_id || 'N/A',
    timestamp: new Date().toISOString()
  }
}];

// Parse Claude diagnosis
const failureData = $('Classify Failure').first().json;
const claudeResponse = $input.first().json;

let diagnosis;
try {
  const content = claudeResponse.content[0].text;
  diagnosis = JSON.parse(content);
} catch (e) {
  diagnosis = {
    root_cause: 'Could not diagnose - Claude parse error',
    severity: 'high',
    affected_service: 'unknown',
    diagnosis: 'Claude API response could not be parsed: ' + e.message,
    recommended_fix: 'Manual investigation required',
    requires_immediate_attention: true
  };
}

return [{
  json: {
    ...failureData,
    diagnosis: diagnosis
  }
}];

// Cleanup: Delete test Event and Client from production MongoDB
// This node prepares the MongoDB delete operations
// The actual deletion will be done via the MongoDB connection

// Option 1: If we have IDs from the Cypress test response (preferred)
// These would be passed through the workflow from the LambdaTest build results

// Option 2: Query by known test data fields
const cleanupQueries = {
  event_query: { 'lead.firstName': 'QATest', 'lead.lastName': 'WeeklyCheck', 'lead.email': 'qa-weekly@starlightmusic.com' },
  client_query: { email: 'qa-weekly@starlightmusic.com' }
};

return [{ json: cleanupQueries }];
